={{ ({
  model: "claude-sonnet-4-6",
  max_tokens: 1200,
  system: "You are an expert stock photography metadata specialist. Analyze the provided photograph and return ONLY a valid JSON object — no markdown fences, no explanation, no preamble.",
  messages: [{
    role: "user",
    content: [
      {
        type: "image",
        source: {
          type: "base64",
          media_type: $json.body.mimeType || "image/jpeg",
          data: $json.body.imageBase64
        }
      },
      {
        type: "text",
        text: "Analyze this stock photograph. Filename hint: \"" + ($json.body.filename || "").replace(/\.[^.]+$/, "").replace(/[-_]/g, " ") + "\".\n\nReturn ONLY this JSON structure:\n{\n  \"title\": \"Descriptive title max 200 chars, factual, capitalise main words\",\n  \"description\": \"2-3 sentences max 200 chars total\",\n  \"keywords\": [\"array of 45-50 keywords-sorted most-specific to most-general\"],\n  \"classification\": \"commercial or editorial\",\n  \"agencies\": [\"subset of: Adobe Stock, Shutterstock, Alamy, Getty Images, Depositphotos, Dreamstime, 123RF\"],\n  \"notes\": \"usage restrictions or empty string\"\n}\n\nAgency rules: commercial (no recognisable people) gets Adobe Stock, Shutterstock, Depositphotos, Dreamstime, 123RF; fine art and landscapes add Getty Images; editorial gets Alamy and Getty Images only; high-quality B&W always include Alamy."
      }
    ]
  }]
}) }}

parameters.jsCode:
const responseText = $json.content?.[0]?.text || '';
let metadata = {};
try {
  const jsonMatch = responseText.match(/{[\s\S]*}/);
  metadata = JSON.parse(jsonMatch ? jsonMatch[0] : responseText);
} catch (e) {
  throw new Error('Failed to parse Claude response: ' + responseText.substring(0, 300));
}

const filename = $("Receive Image from Mac").item.json.body.filename || 'untitled.jpg';
const keywords = Array.isArray(metadata.keywords) ? metadata.keywords : [];
const agencies = Array.isArray(metadata.agencies) ? metadata.agencies : [];
const keywordsStr = keywords.join(', ');
const agenciesStr = agencies.join(', ');
const today = new Date().toISOString().split('T')[0];

function escapeMd(str) {
  return (str || '').replace(/[_*`\[\]()]/g, '\\$&');
}

const reviewMsg =
  'File: ' + escapeMd(filename) + '\n\n' +
  'TITLE:\n' + escapeMd(metadata.title || '') + '\n\n' +
  'DESCRIPTION:\n' + escapeMd(metadata.description || '') + '\n\n' +
  'CLASSIFICATION: ' + escapeMd((metadata.classification || '').toUpperCase()) + '\n' +
  'AGENCIES: ' + escapeMd(agenciesStr) + '\n\n' +
  'KEYWORDS (' + keywords.length + '):\n' + escapeMd(keywordsStr) +
  (metadata.notes ? '\n\nNOTES: ' + escapeMd(metadata.notes) : '');

return {
  json: {
    filename,
    escapedFilename: escapeMd(filename),
    title: metadata.title || '',
    description: metadata.description || '',
    keywords: keywordsStr,
    keywordsCount: keywords.length,
    classification: (metadata.classification || 'commercial').toLowerCase(),
    agencies: agenciesStr,
    notes: metadata.notes || '',
    reviewMsg,
    approvedAt: today,
  }
};
